/**
 * Unit tests for denial-logger PermissionDenied hook
 * Tests JSONL audit trail writing for permission denials
 */

import { describe, test, expect, vi, beforeEach } from 'vitest';
import { denialLogger } from '../../permission-denied/denial-logger.js';
import type { HookInput } from '../../types.js';

// Mock node:fs
vi.mock('node:fs', () => ({
  existsSync: vi.fn(),
  mkdirSync: vi.fn(),
  appendFileSync: vi.fn(),
}));

// Mock the common module
vi.mock('../../lib/common.js', async () => {
  const actual = await vi.importActual<typeof import('../../lib/common.js')>('../../lib/common.js');
  return {
    ...actual,
    logHook: vi.fn(),
    getProjectDir: vi.fn().mockReturnValue('/test/project'),
    outputSilentSuccess: () => ({ continue: true, suppressOutput: true }),
  };
});

import { existsSync, mkdirSync, appendFileSync } from 'node:fs';
import { createTestContext } from '../fixtures/test-context.js';

/**
 * Create a mock HookInput for a denied tool call
 */
function createDeniedInput(
  toolName: string,
  toolInput: Record<string, unknown> = {}
): HookInput {
  return {
    tool_name: toolName,
    session_id: 'test-session-456',
    tool_input: toolInput,
    project_dir: '/test/project',
    hook_event: 'PermissionDenied',
  };
}

let testCtx: ReturnType<typeof createTestContext>;
describe('denial-logger', () => {
  beforeEach(() => {
    testCtx = createTestContext();
    vi.clearAllMocks();
    vi.mocked(existsSync).mockReturnValue(true);
  });

  describe('JSONL audit trail writing', () => {
    test('writes JSONL entry for Bash denial', () => {
      // Arrange
      const input = createDeniedInput('Bash', { command: 'rm -rf /' });

      // Act
      const result = denialLogger(input);

      // Assert
      expect(appendFileSync).toHaveBeenCalledTimes(1);
      const [logPath, content] = vi.mocked(appendFileSync).mock.calls[0];
      expect(logPath).toContain('.claude/feedback/permission-denials.jsonl');

      const entry = JSON.parse((content as string).replace('\n', ''));
      expect(entry.tool_name).toBe('Bash');
      expect(entry.session_id).toBe('test-session-456');
      expect(entry.tool_input_summary).toContain('command:');
      expect(entry.tool_input_summary).toContain('rm -rf /');
      expect(entry.timestamp).toBeDefined();
      expect(result.continue).toBe(true);
    });

    test('writes JSONL entry for Write denial', () => {
      // Arrange
      const input = createDeniedInput('Write', {
        file_path: '/etc/passwd',
        content: 'malicious',
      });

      // Act
      denialLogger(input);

      // Assert
      const [, content] = vi.mocked(appendFileSync).mock.calls[0];
      const entry = JSON.parse((content as string).replace('\n', ''));
      expect(entry.tool_name).toBe('Write');
      expect(entry.tool_input_summary).toContain('file_path:');
      expect(entry.tool_input_summary).toContain('/etc/passwd');
    });

    test('writes JSONL entry for unknown tool input', () => {
      // Arrange
      const input = createDeniedInput('CustomTool', { foo: 'bar' });

      // Act
      denialLogger(input);

      // Assert
      const [, content] = vi.mocked(appendFileSync).mock.calls[0];
      const entry = JSON.parse((content as string).replace('\n', ''));
      expect(entry.tool_input_summary).toBe('unknown input');
    });

    test('truncates long commands to 200 chars', () => {
      // Arrange
      const longCommand = `echo ${'a'.repeat(500)}`;
      const input = createDeniedInput('Bash', { command: longCommand });

      // Act
      denialLogger(input);

      // Assert
      const [, content] = vi.mocked(appendFileSync).mock.calls[0];
      const entry = JSON.parse((content as string).replace('\n', ''));
      // "command: " + 200 chars = 209 total
      expect(entry.tool_input_summary.length).toBeLessThanOrEqual(210);
    });
  });

  describe('Handles missing directory (creates it)', () => {
    test('creates log directory when it does not exist', () => {
      // Arrange
      vi.mocked(existsSync).mockReturnValue(false);
      const input = createDeniedInput('Bash', { command: 'ls' });

      // Act
      denialLogger(input);

      // Assert
      expect(mkdirSync).toHaveBeenCalledWith(
        expect.stringContaining('.claude/feedback'),
        { recursive: true }
      );
      expect(appendFileSync).toHaveBeenCalledTimes(1);
    });

    test('does not create directory when it already exists', () => {
      // Arrange
      vi.mocked(existsSync).mockReturnValue(true);
      const input = createDeniedInput('Bash', { command: 'ls' });

      // Act
      denialLogger(input);

      // Assert
      expect(mkdirSync).not.toHaveBeenCalled();
    });
  });

  describe('Never returns retry', () => {
    test('result never has retry: true for any tool', () => {
      // Arrange
      const tools = ['Bash', 'Write', 'Edit', 'Read', 'Glob', 'Grep'];

      for (const toolName of tools) {
        // Act
        const result = denialLogger(createDeniedInput(toolName, { command: 'git status' }));

        // Assert
        expect(result.hookSpecificOutput?.retry).toBeUndefined();
        expect(result.continue).toBe(true);
        expect(result.suppressOutput).toBe(true);
      }
    });
  });

  describe('Error handling', () => {
    test('gracefully handles appendFileSync failure', () => {
      // Arrange
      vi.mocked(appendFileSync).mockImplementation(() => {
        throw new Error('EACCES: permission denied');
      });
      const input = createDeniedInput('Bash', { command: 'ls' });

      // Act — should not throw
      const result = denialLogger(input);

      // Assert — still returns silent success
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    test('gracefully handles mkdirSync failure', () => {
      // Arrange
      vi.mocked(existsSync).mockReturnValue(false);
      vi.mocked(mkdirSync).mockImplementation(() => {
        throw new Error('EACCES: permission denied');
      });
      const input = createDeniedInput('Bash', { command: 'ls' });

      // Act — should not throw
      const result = denialLogger(input);

      // Assert
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });
  });

  describe('Summarizes input correctly', () => {
    test('summarizes Bash command', () => {
      // Arrange
      const input = createDeniedInput('Bash', { command: 'git push --force' });

      // Act
      denialLogger(input);

      // Assert
      const [, content] = vi.mocked(appendFileSync).mock.calls[0];
      const entry = JSON.parse((content as string).replace('\n', ''));
      expect(entry.tool_input_summary).toBe('command: git push --force');
    });

    test('summarizes file_path for Write/Edit', () => {
      // Arrange
      const input = createDeniedInput('Edit', {
        file_path: '/test/project/src/index.ts',
        old_string: 'old',
        new_string: 'new',
      });

      // Act
      denialLogger(input);

      // Assert
      const [, content] = vi.mocked(appendFileSync).mock.calls[0];
      const entry = JSON.parse((content as string).replace('\n', ''));
      expect(entry.tool_input_summary).toBe('file_path: /test/project/src/index.ts');
    });

    test('summarizes as "unknown input" when no command or file_path', () => {
      // Arrange
      const input = createDeniedInput('SomeTool', { random_field: 'value' });

      // Act
      denialLogger(input);

      // Assert
      const [, content] = vi.mocked(appendFileSync).mock.calls[0];
      const entry = JSON.parse((content as string).replace('\n', ''));
      expect(entry.tool_input_summary).toBe('unknown input');
    });
  });
});
